package org.apache.commons.csv;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVFormat.Predefined;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.function.Executable;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;

class CSVFormatTest {

    @Test
    void testValueOf_withValidFormat() throws Exception {
        // Using reflection to mock Predefined.valueOf and getFormat
        // Save original method references
        Method predefinedValueOfMethod = Predefined.class.getDeclaredMethod("valueOf", String.class);
        Field formatField = null;
        Predefined originalPredefined = null;

        // Create a dummy Predefined mock
        Predefined predefinedMock = Mockito.mock(Predefined.class);
        CSVFormat expectedFormat = CSVFormat.DEFAULT;
        Mockito.when(predefinedMock.getFormat()).thenReturn(expectedFormat);

        // Since Predefined is an enum (most probably), we can't mock static methods with Mockito 3 easily.
        // So we replace the enum constant with a proxy instance by reflection to simulate the behavior.

        // Get the enum constant by name DEFAULT
        originalPredefined = Enum.valueOf(Predefined.class, "DEFAULT");

        // Override the enum constant to return our mock from valueOf(String)
        // Trick: Use a custom enum subclass with overriden getFormat(), but Java doesn't allow.
        // So mock the whole CSVFormat.valueOf by reflection to use our mock

        // Instead, we use a small helper class with reflection to override the behavior of CSVFormat.valueOf temporarily.
        // Since the original method calls Predefined.valueOf(format).getFormat(), we mock Predefined.valueOf by reflection.

        // Define a helper and swap it only within this test:
        // Actually, better to mock CSVFormat.valueOf to call the mock.

        // But the user asked to test CSVFormat.valueOf "calling Predefined.valueOf" and fix compilation issue.
        // So, better to mock Predefined.valueOf via reflection:

        // Predefined is an enum with a method valueOf(String) auto-generated by compiler,
        // so we can't override or mock static method easily.

        // So instead, reflectively access the `Predefined.valueOf(String)` method for the test:
        // Call CSVFormat.valueOf("DEFAULT") and assert it returns DEFAULT constant.

        // So here just call it directly without mocking since mocking static not possible.

        CSVFormat actual = CSVFormat.valueOf("DEFAULT");
        assertSame(expectedFormat, actual);
    }

    @Test
    void testValueOf_withNullFormat_throwsException() {
        assertThrows(NullPointerException.class, () -> CSVFormat.valueOf(null));
    }

    @Test
    void testValueOf_withInvalidFormat_throwsIllegalArgumentException() {
        assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf("INVALID_FORMAT"));
    }
}
